86	type PolicyContext = { customer: Customer; isFollowUp: boolean };
87	
88	type PolicyDiscountRule = { rate: number; applies: (context: PolicyContext) => boolean };
89	
90	const POLICY_DISCOUNT_RULES: PolicyDiscountRule[] = [
91	  {
92	    rate: LOYALTY_DISCOUNT_RATE,
93	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD,
94	  },
95	  {
96	    rate: FOLLOW_UP_DISCOUNT_RATE,
97	    applies: ({ isFollowUp }) => isFollowUp,
98	  },
99	];
100	
101	const policyDiscountsFor = (base: number, context: PolicyContext): number =>
102	  POLICY_DISCOUNT_RULES.reduce(
103	    (total, rule) => (rule.applies(context) ? total + base * rule.rate : total),
104	    0,
105	  );
