107	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): QuoteResult => {
108	  const base = basePremiumFor(items);
109	  const surcharges = surchargesFor(items);
110	  const discounts = policyDiscountsFor(base, { customer, isFollowUp });
111	  return {
112	    premium: Math.ceil(base + surcharges - discounts + base * FIRST_INSURANCE_RATE + PROCESSING_FEE),
113	  };
114	};
115	
116	const isFollowUpStep = (index: number): boolean => index > 0;
117	
118	type Policy = { items: Item[]; remainingCap: number };
119	
120	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
121	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
122	
123	const insuranceSumFor = (items: Item[]): number =>
124	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
125	
126	const createPolicy = (items: Item[]): Policy => ({
127	  items,
128	  remainingCap: CAP_MULTIPLIER * insuranceSumFor(items),
129	});
130	
131	const reimbursementFor = (item: Item, amount: number): number =>
132	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
133	    ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE
134	    : amount;
135	
136	const payoutForDamage = (damage: Damage, policy: Policy): number => {
137	  const item = policy.items.find((it) => it.type === damage.itemType);
138	  const reimbursement = item ? reimbursementFor(item, damage.amount) : damage.amount;
139	  return Math.max(0, reimbursement - DEDUCTIBLE);
140	};
141	
142	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
143	  const payout = incident.damages.reduce(
144	    (sum, damage) => sum + payoutForDamage(damage, policy),
145	    0,
146	  );
147	  policy.remainingCap -= payout;
148	  return { payout, remainingCap: policy.remainingCap };
149	};
