151	const handleQuoteStep = (
152	  step: QuoteStep,
153	  index: number,
154	  customer: Customer,
155	  policies: Policy[],
156	): QuoteResult => {
157	  policies[index] = createPolicy(step.items);
158	  return quotePremium(step.items, customer, isFollowUpStep(index));
159	};
160	
161	const handleClaimStep = (step: ClaimStep, policies: Policy[]): ClaimResult =>
162	  processClaim(policies[step.policy], step.incident);
163	
164	const handleStep = (
165	  step: Step,
166	  index: number,
167	  customer: Customer,
168	  policies: Policy[],
169	): StepResult =>
170	  step.op === "quote"
171	    ? handleQuoteStep(step, index, customer, policies)
172	    : handleClaimStep(step, policies);
173	
174	export const processScenario = ({ customer, steps }: Scenario): { results: StepResult[] } => {
175	  const policies: Policy[] = [];
176	  const results = steps.map((step, index) => handleStep(step, index, customer, policies));
177	  return { results };
178	};
